// =============================================================
// Clerk Webhook - مزامنة اليوزرية مع Supabase
// بيستقبل أحداث user.created و user.updated من Clerk
// =============================================================

import { Hono } from 'hono'
import { Webhook } from 'svix'
import type { Env } from '../index'

type WebhookEvent =
  | { type: 'user.created'; data: ClerkUserData }
  | { type: 'user.updated'; data: ClerkUserData }
  | { type: 'user.deleted'; data: { id: string } }

interface ClerkUserData {
  id: string
  first_name: string | null
  last_name: string | null
  email_addresses: Array<{ email_address: string; id: string }>
  phone_numbers: Array<{ phone_number: string; id: string }>
  image_url: string
  primary_email_address_id: string | null
  primary_phone_number_id: string | null
}

export const webhookRouter = new Hono<{ Bindings: Env }>()

webhookRouter.post('/clerk', async (c) => {
  const webhookSecret = c.env.CLERK_WEBHOOK_SECRET

  if (!webhookSecret) {
    console.error('CLERK_WEBHOOK_SECRET غير موجود')
    return c.json({ error: 'Webhook secret not configured' }, 500)
  }

  // جيب الـ headers المطلوبة للتحقق
  const svixId = c.req.header('svix-id')
  const svixTimestamp = c.req.header('svix-timestamp')
  const svixSignature = c.req.header('svix-signature')

  if (!svixId || !svixTimestamp || !svixSignature) {
    return c.json({ error: 'Missing svix headers' }, 400)
  }

  // جيب الـ body كـ raw text
  const body = await c.req.text()

  // تحقق من صحة الـ webhook signature
  const wh = new Webhook(webhookSecret)
  let event: WebhookEvent

  try {
    event = wh.verify(body, {
      'svix-id': svixId,
      'svix-timestamp': svixTimestamp,
      'svix-signature': svixSignature,
    }) as WebhookEvent
  } catch (err) {
    console.error('Webhook signature verification failed:', err)
    return c.json({ error: 'Invalid signature' }, 400)
  }

  // جيب Supabase client
  const { createClient } = await import('@supabase/supabase-js')
  const supabase = createClient(c.env.SUPABASE_URL, c.env.SUPABASE_SERVICE_ROLE_KEY)

  try {
    if (event.type === 'user.created') {
      await handleUserCreated(supabase, event.data)
    } else if (event.type === 'user.updated') {
      await handleUserUpdated(supabase, event.data)
    } else if (event.type === 'user.deleted') {
      await handleUserDeleted(supabase, event.data.id)
    }

    return c.json({ success: true, type: event.type })
  } catch (err) {
    console.error('Webhook handler error:', err)
    return c.json({ error: 'Handler error' }, 500)
  }
})

async function handleUserCreated(supabase: ReturnType<typeof import('@supabase/supabase-js').createClient>, data: ClerkUserData) {
  const primaryEmail = data.email_addresses.find(e => e.id === data.primary_email_address_id)
  const primaryPhone = data.phone_numbers.find(p => p.id === data.primary_phone_number_id)

  const name = [data.first_name, data.last_name].filter(Boolean).join(' ') || 'مستخدم جديد'

  const { error } = await supabase
    .from('users')
    .insert({
      clerk_id: data.id,
      name,
      email: primaryEmail?.email_address || null,
      phone: primaryPhone?.phone_number || null,
      avatar_url: data.image_url || null,
      role: 'CLIENT',
      created_at: new Date().toISOString(),
    })

  if (error) {
    // لو موجود مسبقاً ignore
    if (error.code === '23505') {
      console.log('User already exists, skipping insert:', data.id)
      return
    }
    console.error('Error creating user in Supabase:', error)
    throw error
  }

  console.log('User created in Supabase:', data.id, name)
}

async function handleUserUpdated(supabase: ReturnType<typeof import('@supabase/supabase-js').createClient>, data: ClerkUserData) {
  const primaryEmail = data.email_addresses.find(e => e.id === data.primary_email_address_id)
  const primaryPhone = data.phone_numbers.find(p => p.id === data.primary_phone_number_id)

  const name = [data.first_name, data.last_name].filter(Boolean).join(' ') || null

  const { error } = await supabase
    .from('users')
    .update({
      name: name || undefined,
      email: primaryEmail?.email_address || null,
      phone: primaryPhone?.phone_number || null,
      avatar_url: data.image_url || null,
      updated_at: new Date().toISOString(),
    })
    .eq('clerk_id', data.id)

  if (error) {
    console.error('Error updating user in Supabase:', error)
    throw error
  }

  console.log('User updated in Supabase:', data.id)
}

async function handleUserDeleted(supabase: ReturnType<typeof import('@supabase/supabase-js').createClient>, clerkId: string) {
  const { error } = await supabase
    .from('users')
    .update({ deleted_at: new Date().toISOString() })
    .eq('clerk_id', clerkId)

  if (error) {
    console.error('Error soft-deleting user in Supabase:', error)
    throw error
  }

  console.log('User soft-deleted in Supabase:', clerkId)
}

