// =============================================================
// Auth Context - Clerk Real Auth + Supabase Role
// =============================================================

import { createContext, useContext, useEffect, useState, ReactNode } from 'react'
import { useUser, useClerk } from '@clerk/clerk-react'

export type UserRole = 'client' | 'courier' | 'admin' | null

export interface AppUser {
  id: string
  clerkId: string
  name: string
  phone: string | null
  email: string | null
  role: UserRole
  avatar: string | null
}

interface AuthContextType {
  user: AppUser | null
  role: UserRole
  isLoggedIn: boolean
  isLoading: boolean
  logout: () => Promise<void>
  refreshUser: () => Promise<void>
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  role: null,
  isLoggedIn: false,
  isLoading: true,
  logout: async () => {},
  refreshUser: async () => {},
})

const BACKEND_URL = import.meta.env.VITE_BACKEND_URL || 'http://localhost:8787'

export function AuthProvider({ children }: { children: ReactNode }) {
  const { user: clerkUser, isLoaded: clerkLoaded, isSignedIn } = useUser()
  const { signOut } = useClerk()
  const [appUser, setAppUser] = useState<AppUser | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  async function fetchUserProfile(token: string) {
    try {
      const res = await fetch(`${BACKEND_URL}/api/users/me`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      if (res.ok) {
        const data = await res.json() as { id: string; name: string; phone: string | null; email: string | null; role: string; clerk_id: string; avatar_url: string | null }
        return data
      }
    } catch {
      // fallback: use Clerk data directly
    }
    return null
  }

  async function syncUser() {
    if (!clerkLoaded) return

    if (!isSignedIn || !clerkUser) {
      setAppUser(null)
      setIsLoading(false)
      return
    }

    setIsLoading(true)

    try {
      // جيب token من Clerk
      const token = await clerkUser.getIdToken?.() || ''

      // حاول تجيب بيانات اليوزر من الـ backend
      const profile = token ? await fetchUserProfile(token) : null

      if (profile) {
        const roleMap: Record<string, UserRole> = {
          CLIENT: 'client',
          COURIER: 'courier',
          ADMIN: 'admin',
        }
        setAppUser({
          id: profile.id,
          clerkId: clerkUser.id,
          name: profile.name || clerkUser.fullName || 'مستخدم',
          phone: profile.phone || clerkUser.primaryPhoneNumber?.phoneNumber || null,
          email: profile.email || clerkUser.primaryEmailAddress?.emailAddress || null,
          role: roleMap[profile.role] || 'client',
          avatar: profile.avatar_url || clerkUser.imageUrl || null,
        })
      } else {
        // Backend غير متاح - استخدم بيانات Clerk مباشرة مع role افتراضي
        setAppUser({
          id: clerkUser.id,
          clerkId: clerkUser.id,
          name: clerkUser.fullName || clerkUser.firstName || 'مستخدم',
          phone: clerkUser.primaryPhoneNumber?.phoneNumber || null,
          email: clerkUser.primaryEmailAddress?.emailAddress || null,
          role: 'client',
          avatar: clerkUser.imageUrl || null,
        })
      }
    } catch (err) {
      console.error('Error syncing user:', err)
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    syncUser()
  }, [clerkLoaded, isSignedIn, clerkUser?.id])

  async function logout() {
    await signOut()
    setAppUser(null)
  }

  async function refreshUser() {
    await syncUser()
  }

  return (
    <AuthContext.Provider value={{
      user: appUser,
      role: appUser?.role || null,
      isLoggedIn: !!appUser,
      isLoading,
      logout,
      refreshUser,
    }}>
      {children}
    </AuthContext.Provider>
  )
}

export const useAuth = () => useContext(AuthContext)

import React from 'react'
import ReactDOM from 'react-dom/client'
import { BrowserRouter } from 'react-router-dom'
import { ClerkProvider } from '@clerk/clerk-react'
import { Toaster } from 'react-hot-toast'
import App from './App'
import { AuthProvider } from './lib/auth-context'
import { NotificationsProvider } from './lib/notifications-context'
import './styles/globals.css'

const CLERK_PUBLISHABLE_KEY = import.meta.env.VITE_CLERK_PUBLISHABLE_KEY

function AppWithProviders() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <NotificationsProvider>
          <App />
          <Toaster
            position="top-center"
            toastOptions={{
              duration: 4000,
              style: {
                fontFamily: 'Cairo, sans-serif',
                direction: 'rtl',
                borderRadius: '12px',
                padding: '12px 16px',
                fontSize: '14px',
              },
              success: {
                style: { background: '#10b981', color: '#fff' },
                iconTheme: { primary: '#fff', secondary: '#10b981' },
              },
              error: {
                style: { background: '#ef4444', color: '#fff' },
                iconTheme: { primary: '#fff', secondary: '#ef4444' },
              },
            }}
          />
        </NotificationsProvider>
      </AuthProvider>
    </BrowserRouter>
  )
}

ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    {CLERK_PUBLISHABLE_KEY ? (
      <ClerkProvider publishableKey={CLERK_PUBLISHABLE_KEY}>
        <AppWithProviders />
      </ClerkProvider>
    ) : (
      // Demo Mode - بدون Clerk keys
      <AppWithProviders />
    )}
  </React.StrictMode>
)

// =============================================================
// Auth Context - Clerk Real Auth + Supabase Role
// بيدعم Demo Mode لما CLERK_PUBLISHABLE_KEY مش موجود
// =============================================================

import { createContext, useContext, useEffect, useState, ReactNode } from 'react'

export type UserRole = 'client' | 'courier' | 'admin' | null

export interface AppUser {
  id: string
  clerkId?: string
  name: string
  phone: string | null
  email: string | null
  role: UserRole
  avatar: string | null
  isDemo?: boolean
}

interface AuthContextType {
  user: AppUser | null
  role: UserRole
  isLoggedIn: boolean
  isLoading: boolean
  logout: () => Promise<void>
  refreshUser: () => Promise<void>
  // Demo Mode (backward compat)
  demoLogin?: (role: UserRole) => void
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  role: null,
  isLoggedIn: false,
  isLoading: false,
  logout: async () => {},
  refreshUser: async () => {},
})

const BACKEND_URL = import.meta.env.VITE_BACKEND_URL || 'http://localhost:8787'

// ==============================
// Real Clerk Auth Provider
// ==============================
export function ClerkAuthProvider({ children }: { children: ReactNode }) {
  // Dynamic import of Clerk hooks to avoid errors when ClerkProvider not mounted
  const [clerkState, setClerkState] = useState<{
    loaded: boolean
    signedIn: boolean
    userId?: string
    getToken?: () => Promise<string>
    signOut?: () => Promise<void>
    fullName?: string
    firstName?: string
    phone?: string
    email?: string
    imageUrl?: string
  }>({ loaded: false, signedIn: false })

  const [appUser, setAppUser] = useState<AppUser | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  useEffect(() => {
    // Dynamically import Clerk to safely detect state
    let unsubscribe: (() => void) | undefined

    async function initClerk() {
      try {
        const { useUser, useClerk } = await import('@clerk/clerk-react')
        // We can't call hooks from useEffect directly, so we use window.__clerk__ instead
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        const clerkInstance = (window as any).__clerk_frontend_api

        if (clerkInstance) {
          // Use Clerk's client directly
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          const clerk = (window as any).Clerk
          if (clerk?.user) {
            const u = clerk.user
            setClerkState({
              loaded: true,
              signedIn: true,
              userId: u.id,
              getToken: () => clerk.session?.getToken(),
              signOut: () => clerk.signOut(),
              fullName: u.fullName,
              firstName: u.firstName,
              phone: u.primaryPhoneNumber?.phoneNumber,
              email: u.primaryEmailAddress?.emailAddress,
              imageUrl: u.imageUrl,
            })
          } else {
            setClerkState({ loaded: true, signedIn: false })
          }
        } else {
          setClerkState({ loaded: true, signedIn: false })
        }
      } catch {
        setClerkState({ loaded: true, signedIn: false })
      }
    }

    initClerk()

    return () => { unsubscribe?.() }
  }, [])

  useEffect(() => {
    if (!clerkState.loaded) return
    syncUser()
  }, [clerkState.loaded, clerkState.signedIn, clerkState.userId])

  async function syncUser() {
    if (!clerkState.signedIn || !clerkState.userId) {
      setAppUser(null)
      setIsLoading(false)
      return
    }

    setIsLoading(true)

    try {
      const token = clerkState.getToken ? await clerkState.getToken() : ''

      let profile = null
      if (token) {
        try {
          const res = await fetch(`${BACKEND_URL}/api/users/me`, {
            headers: { Authorization: `Bearer ${token}` },
          })
          if (res.ok) profile = await res.json()
        } catch { /* backend unavailable */ }
      }

      const roleMap: Record<string, UserRole> = {
        CLIENT: 'client', COURIER: 'courier', ADMIN: 'admin',
      }

      setAppUser({
        id: profile?.id || clerkState.userId || '',
        clerkId: clerkState.userId,
        name: profile?.name || clerkState.fullName || clerkState.firstName || 'مستخدم',
        phone: profile?.phone || clerkState.phone || null,
        email: profile?.email || clerkState.email || null,
        role: profile?.role ? (roleMap[profile.role] || 'client') : 'client',
        avatar: profile?.avatar_url || clerkState.imageUrl || null,
      })
    } catch (err) {
      console.error('Error syncing user:', err)
    } finally {
      setIsLoading(false)
    }
  }

  return (
    <AuthContext.Provider value={{
      user: appUser,
      role: appUser?.role || null,
      isLoggedIn: !!appUser,
      isLoading,
      logout: async () => {
        await clerkState.signOut?.()
        setAppUser(null)
      },
      refreshUser: syncUser,
    }}>
      {children}
    </AuthContext.Provider>
  )
}

// ==============================
// Demo Mode Provider (بدون Clerk)
// ==============================
const DEMO_USERS: Record<NonNullable<UserRole>, AppUser> = {
  client:  { id: 'demo-client',  name: 'أحمد العميل',   phone: '01012345678', email: null, role: 'client',  avatar: null, isDemo: true },
  courier: { id: 'demo-courier', name: 'محمد المندوب',  phone: '01098765432', email: null, role: 'courier', avatar: null, isDemo: true },
  admin:   { id: 'demo-admin',   name: 'أدمن المنصة',   phone: '01111111111', email: null, role: 'admin',   avatar: null, isDemo: true },
}

export function DemoAuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AppUser | null>(() => {
    try {
      const saved = localStorage.getItem('mandoubak_demo_user')
      return saved ? JSON.parse(saved) : null
    } catch { return null }
  })

  function demoLogin(role: UserRole) {
    if (!role) return
    const demoUser = DEMO_USERS[role]
    setUser(demoUser)
    localStorage.setItem('mandoubak_demo_user', JSON.stringify(demoUser))
  }

  function logout() {
    setUser(null)
    localStorage.removeItem('mandoubak_demo_user')
    return Promise.resolve()
  }

  return (
    <AuthContext.Provider value={{
      user,
      role: user?.role || null,
      isLoggedIn: !!user,
      isLoading: false,
      logout,
      refreshUser: async () => {},
      demoLogin,
    }}>
      {children}
    </AuthContext.Provider>
  )
}

// ==============================
// Smart Provider - يختار تلقائياً
// ==============================
export function AuthProvider({ children }: { children: ReactNode }) {
  const hasClerkKey = !!import.meta.env.VITE_CLERK_PUBLISHABLE_KEY

  if (hasClerkKey) {
    return <ClerkAuthProvider>{children}</ClerkAuthProvider>
  }

  return <DemoAuthProvider>{children}</DemoAuthProvider>
}

export const useAuth = () => useContext(AuthContext)

