function ClerkAuthProviderInner({ children }: { children: ReactNode }) {
  // These imports are safe here because this component is only rendered inside ClerkProvider
  // eslint-disable-next-line @typescript-eslint/no-var-requires
  const { useUser, useClerk } = require('@clerk/clerk-react') as typeof import('@clerk/clerk-react')
  const { user: clerkUser, isLoaded, isSignedIn } = useUser()
  const { signOut } = useClerk()

  const [appUser, setAppUser] = useState<AppUser | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  async function syncUser() {
    if (!isLoaded) return

    if (!isSignedIn || !clerkUser) {
      setAppUser(null)
      setIsLoading(false)
      return
    }

    setIsLoading(true)

    try {
      // جيب JWT token من Clerk
      const token = await clerkUser.getIdToken?.() || await (clerkUser as unknown as { getToken: () => Promise<string> }).getToken?.() || ''

      let profile = null
