import { createContext, useContext, useEffect, useState, ReactNode } from 'react'
import { useUser, useClerk } from '@clerk/clerk-react'
import type { AuthContextType, AppUser, UserRole } from './auth-context'

const BACKEND_URL = import.meta.env.VITE_BACKEND_URL || 'http://localhost:8787'

interface ClerkAuthInnerProps {
  AuthContext: React.Context<AuthContextType>
  children: ReactNode
}

export function ClerkAuthProviderInner({ AuthContext, children }: ClerkAuthInnerProps) {
  const { user: clerkUser, isLoaded, isSignedIn } = useUser()
  const { signOut } = useClerk()

  const [appUser, setAppUser] = useState<AppUser | null>(null)
  const [isLoading, setIsLoading] = useState(true)

  async function syncUser() {
    if (!isLoaded) return

    if (!isSignedIn || !clerkUser) {
      setAppUser(null)
      setIsLoading(false)
      return
    }

    setIsLoading(true)

    try {
      // جيب Clerk session token
      const token = await clerkUser.getIdToken?.() || ''

      let profile: { id: string; name: string; phone: string | null; email: string | null; role: string; avatar_url: string | null } | null = null

      if (token) {
        try {
          const res = await fetch(`${BACKEND_URL}/api/users/me`, {
            headers: { Authorization: `Bearer ${token}` },
          })
          if (res.ok) profile = await res.json()
        } catch { /* backend unavailable */ }
      }

      const roleMap: Record<string, UserRole> = {
        CLIENT: 'client', COURIER: 'courier', ADMIN: 'admin',
      }

      setAppUser({
        id: profile?.id || clerkUser.id,
        clerkId: clerkUser.id,
        name: profile?.name || clerkUser.fullName || clerkUser.firstName || 'مستخدم',
        phone: profile?.phone || clerkUser.primaryPhoneNumber?.phoneNumber || null,
        email: profile?.email || clerkUser.primaryEmailAddress?.emailAddress || null,
        role: profile?.role ? (roleMap[profile.role] || 'client') : 'client',
        avatar: profile?.avatar_url || clerkUser.imageUrl || null,
      })
    } catch (err) {
      console.error('Error syncing user:', err)
    } finally {
      setIsLoading(false)
    }
  }

  useEffect(() => {
    syncUser()
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isLoaded, isSignedIn, clerkUser?.id])

  return (
    <AuthContext.Provider value={{
      user: appUser,
      role: appUser?.role || null,
      isLoggedIn: !!appUser,
      isLoading: !isLoaded || isLoading,
      logout: async () => {
        await signOut()
        setAppUser(null)
      },
      refreshUser: syncUser,
    }}>
      {children}
    </AuthContext.Provider>
  )
}

