  const [user, setUser] = useState<AppUser | null>(() => {
    try {
      const saved = localStorage.getItem('mandoubak_demo_user')
      return saved ? JSON.parse(saved) : null
    } catch { return null }
  })

  function demoLogin(role: UserRole) {
    if (!role) return
