// =============================================================
// Auth Context - تسجيل مباشر (اسم + تليفون)
// بدون Clerk - بيحفظ في Supabase + localStorage
// =============================================================

import { createContext, useContext, useState, ReactNode } from 'react'

export type UserRole = 'client' | 'courier' | 'admin' | null

export interface AppUser {
  id: string
  name: string
  phone: string
  email: string | null
  role: UserRole
  avatar: string | null
  onboarded?: boolean
}

export interface AuthContextType {
  user: AppUser | null
  role: UserRole
  isLoggedIn: boolean
  isLoading: boolean
  needsOnboarding: boolean
  login: (user: AppUser) => void
  logout: () => Promise<void>
  refreshUser: () => Promise<void>
  updateRole: (role: UserRole) => void
  // legacy demo compat
  demoLogin?: (role: UserRole) => void
}

export const AuthContext = createContext<AuthContextType>({
  user: null,
  role: null,
  isLoggedIn: false,
  isLoading: false,
  needsOnboarding: false,
  login: () => {},
  logout: async () => {},
  refreshUser: async () => {},
  updateRole: () => {},
})

const STORAGE_KEY = 'mandoubak_user'

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<AppUser | null>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY)
      return saved ? JSON.parse(saved) : null
    } catch { return null }
  })

  function login(appUser: AppUser) {
    setUser(appUser)
    localStorage.setItem(STORAGE_KEY, JSON.stringify(appUser))
  }

  async function logout() {
    setUser(null)
    localStorage.removeItem(STORAGE_KEY)
  }

  function updateRole(role: UserRole) {
    if (!user || !role) return
    const updated = { ...user, role, onboarded: true }
    setUser(updated)
    localStorage.setItem(STORAGE_KEY, JSON.stringify(updated))
  }

  async function refreshUser() {
    // إعادة قراءة من localStorage
    try {
      const saved = localStorage.getItem(STORAGE_KEY)
      if (saved) setUser(JSON.parse(saved))
    } catch { /* ignore */ }
  }

  const needsOnboarding = !!user && user.onboarded === false

  return (
    <AuthContext.Provider value={{
      user,
      role: user?.role || null,
      isLoggedIn: !!user,
      isLoading: false,
      needsOnboarding,
      login,
      logout,
      refreshUser,
      updateRole,
      demoLogin: (role) => {
        if (!user || !role) return
        updateRole(role)
      },
    }}>
      {children}
    </AuthContext.Provider>
  )
}

export const useAuth = () => useContext(AuthContext)

// =============================================================
// Login / Register Page - تسجيل مباشر بدون Clerk
// =============================================================

import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Truck, Phone, User, ArrowLeft, Eye, EyeOff, Loader2 } from 'lucide-react'
import { useAuth } from '../../lib/auth-context'
import type { AppUser } from '../../lib/auth-context'
import toast from 'react-hot-toast'

type Mode = 'welcome' | 'register' | 'login'

const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL
const SUPABASE_ANON_KEY = import.meta.env.VITE_SUPABASE_ANON_KEY

// حفظ اليوزر في Supabase عبر anon key
async function saveUserToSupabase(user: Omit<AppUser, 'id'> & { id?: string }): Promise<string | null> {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY?.startsWith('eyJ')) return null

  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/users`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        apikey: SUPABASE_ANON_KEY,
        Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
        Prefer: 'return=representation',
      },
      body: JSON.stringify({
        name: user.name,
        phone: user.phone,
        email: user.email,
        role: user.role?.toUpperCase() || 'CLIENT',
        onboarded: true,
        clerk_id: `local_${user.phone}`,
      }),
    })

    if (res.ok) {
      const [saved] = await res.json()
      return saved?.id || null
    }
  } catch { /* ignore - local mode */ }
  return null
}

// جلب يوزر بالتليفون
async function findUserByPhone(phone: string): Promise<AppUser | null> {
  if (!SUPABASE_URL || !SUPABASE_ANON_KEY?.startsWith('eyJ')) return null

  try {
    const res = await fetch(
      `${SUPABASE_URL}/rest/v1/users?phone=eq.${encodeURIComponent(phone)}&select=*&limit=1`,
      {
        headers: {
          apikey: SUPABASE_ANON_KEY,
          Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
        },
      }
    )
    if (res.ok) {
      const [found] = await res.json()
      if (found) {
        const roleMap: Record<string, AppUser['role']> = {
          CLIENT: 'client', COURIER: 'courier', ADMIN: 'admin',
        }
        return {
          id: found.id,
          name: found.name,
          phone: found.phone,
          email: found.email,
          role: roleMap[found.role] || 'client',
          avatar: found.avatar_url,
          onboarded: found.onboarded,
        }
      }
    }
  } catch { /* ignore */ }
  return null
}

export default function LoginPage() {
  const { login, isLoggedIn, user } = useAuth()
  const navigate = useNavigate()
  const [mode, setMode] = useState<Mode>('welcome')
  const [loading, setLoading] = useState(false)

  // بيانات التسجيل
  const [name, setName] = useState('')
  const [phone, setPhone] = useState('')
  const [showPhone, setShowPhone] = useState(false)

  // لو بالفعل مسجل دخول
  if (isLoggedIn && user) {
    const dest = user.role === 'courier' ? '/courier/dashboard' : user.role === 'admin' ? '/admin' : '/'
    navigate(dest, { replace: true })
    return null
  }

  // ===== تسجيل جديد =====
  async function handleRegister(e: React.FormEvent) {
    e.preventDefault()
    if (!name.trim() || name.trim().length < 2) {
      toast.error('اكتب اسمك الكامل')
      return
    }
    const cleanPhone = phone.replace(/\D/g, '')
    if (cleanPhone.length < 10) {
      toast.error('رقم التليفون غلط')
      return
    }

    setLoading(true)
    try {
      // تحقق لو الرقم موجود
      const existing = await findUserByPhone(cleanPhone)
      if (existing) {
        login(existing)
        toast.success(`أهلاً ${existing.name}! 👋`)
        const dest = existing.role === 'courier' ? '/courier/dashboard' : '/'
        navigate(dest, { replace: true })
        return
      }

      // إنشاء حساب جديد
      const newId = `local_${Date.now()}`
      const newUser: AppUser = {
        id: newId,
        name: name.trim(),
        phone: cleanPhone,
        email: null,
        role: 'client',
        avatar: null,
        onboarded: false, // هيروح صفحة اختيار الدور
      }

      // حاول تحفظ في Supabase
      const supabaseId = await saveUserToSupabase(newUser)
      if (supabaseId) newUser.id = supabaseId

      login(newUser)
      toast.success(`أهلاً ${newUser.name}! 🎉`)
      navigate('/onboarding', { replace: true })
    } finally {
      setLoading(false)
    }
  }

  // ===== دخول بالتليفون =====
  async function handleLogin(e: React.FormEvent) {
    e.preventDefault()
    const cleanPhone = phone.replace(/\D/g, '')
    if (cleanPhone.length < 10) {
      toast.error('رقم التليفون غلط')
      return
    }

    setLoading(true)
    try {
      const found = await findUserByPhone(cleanPhone)
      if (found) {
        login(found)
        toast.success(`أهلاً ${found.name}! 👋`)
        const dest = found.role === 'courier' ? '/courier/dashboard' : found.role === 'admin' ? '/admin' : '/'
        navigate(dest, { replace: true })
      } else {
        toast.error('الرقم مش موجود — سجّل حساب جديد')
        setMode('register')
      }
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-[85vh] flex items-center justify-center">
      <div className="w-full max-w-sm space-y-6">

        {/* Logo */}
        <div className="text-center">
          <div className="w-20 h-20 bg-orange-500 rounded-3xl flex items-center justify-center mx-auto mb-4 shadow-xl shadow-orange-200">
            <Truck className="text-white" size={36} />
          </div>
          <h1 className="text-3xl font-black text-gray-900">مندوبك</h1>
          <p className="text-gray-500 mt-1">منصة التوصيل السريع</p>
        </div>

        {/* Welcome Screen */}
        {mode === 'welcome' && (
          <div className="space-y-3">
            <button
              onClick={() => setMode('register')}
              className="w-full bg-orange-500 hover:bg-orange-600 text-white font-black text-lg py-4 rounded-2xl shadow-lg shadow-orange-200 transition-all active:scale-95"
            >
              🚀 حساب جديد
            </button>
            <button
              onClick={() => setMode('login')}
              className="w-full bg-white border-2 border-gray-200 hover:border-orange-300 hover:bg-orange-50 text-gray-800 font-bold text-lg py-4 rounded-2xl transition-all"
            >
              دخول بحسابي
            </button>
          </div>
        )}

        {/* Register Form */}
        {mode === 'register' && (
          <form onSubmit={handleRegister} className="space-y-4">
            <div className="bg-green-50 border border-green-200 rounded-2xl p-3 text-center">
              <span className="text-green-700 text-sm font-bold">✨ تسجيل مجاني — بدون إيميل أو كلمة سر</span>
            </div>

            {/* الاسم */}
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2 text-right">الاسم الكامل</label>
              <div className="relative">
                <User size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type="text"
                  value={name}
                  onChange={e => setName(e.target.value)}
                  placeholder="محمد أحمد"
                  required
                  className="w-full pr-10 pl-4 py-3.5 border-2 border-gray-200 rounded-2xl focus:border-orange-400 focus:outline-none text-right font-medium bg-white"
                  dir="rtl"
                />
              </div>
            </div>

            {/* التليفون */}
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2 text-right">رقم التليفون</label>
              <div className="relative">
                <Phone size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type={showPhone ? 'text' : 'tel'}
                  value={phone}
                  onChange={e => setPhone(e.target.value)}
                  placeholder="01xxxxxxxxx"
                  required
                  className="w-full pr-10 pl-10 py-3.5 border-2 border-gray-200 rounded-2xl focus:border-orange-400 focus:outline-none text-right font-medium bg-white tracking-wider"
                  dir="ltr"
                />
                <button type="button" onClick={() => setShowPhone(!showPhone)}
                  className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600">
                  {showPhone ? <EyeOff size={16} /> : <Eye size={16} />}
                </button>
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-orange-500 hover:bg-orange-600 disabled:bg-gray-200 disabled:text-gray-400 text-white font-black text-lg py-4 rounded-2xl shadow-lg shadow-orange-200 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              {loading ? <><Loader2 size={20} className="animate-spin" /> جاري التسجيل...</> : 'ابدأ الآن →'}
            </button>

            <button type="button" onClick={() => setMode('welcome')}
              className="w-full flex items-center justify-center gap-1 text-gray-500 text-sm hover:text-gray-700 transition-colors">
              <ArrowLeft size={14} /> رجوع
            </button>
          </form>
        )}

        {/* Login Form */}
        {mode === 'login' && (
          <form onSubmit={handleLogin} className="space-y-4">
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2 text-right">رقم التليفون</label>
              <div className="relative">
                <Phone size={18} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" />
                <input
                  type="tel"
                  value={phone}
                  onChange={e => setPhone(e.target.value)}
                  placeholder="01xxxxxxxxx"
                  required
                  className="w-full pr-10 pl-4 py-3.5 border-2 border-gray-200 rounded-2xl focus:border-orange-400 focus:outline-none text-right font-medium bg-white tracking-wider"
                  dir="ltr"
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full bg-orange-500 hover:bg-orange-600 disabled:bg-gray-200 disabled:text-gray-400 text-white font-black text-lg py-4 rounded-2xl shadow-lg shadow-orange-200 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              {loading ? <><Loader2 size={20} className="animate-spin" /> جاري الدخول...</> : 'دخول →'}
            </button>

            <button type="button" onClick={() => setMode('welcome')}
              className="w-full flex items-center justify-center gap-1 text-gray-500 text-sm hover:text-gray-700 transition-colors">
              <ArrowLeft size={14} /> رجوع
            </button>
          </form>
        )}

        <p className="text-center text-xs text-gray-400">
          بالتسجيل أنت موافق على شروط الاستخدام وسياسة الخصوصية
        </p>
      </div>
    </div>
  )
}

// =============================================================
// Onboarding - اختيار الدور بعد التسجيل الأول
// =============================================================

import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Truck, ShoppingBag, ChevronLeft, Loader2 } from 'lucide-react'
import { useAuth } from '../lib/auth-context'
import toast from 'react-hot-toast'

export default function OnboardingPage() {
  const { user, updateRole, isLoggedIn } = useAuth()
  const navigate = useNavigate()
  const [selected, setSelected] = useState<'client' | 'courier' | null>(null)
  const [loading, setLoading] = useState(false)

  // مش مسجل → روح للتسجيل
  if (!isLoggedIn) {
    navigate('/login', { replace: true })
    return null
  }

  async function handleConfirm() {
    if (!selected) return
    setLoading(true)

    try {
      updateRole(selected)
      await new Promise(r => setTimeout(r, 400)) // smooth UX

      toast.success(
        selected === 'client' ? '🎉 أهلاً! حسابك كعميل جاهز' : '🛵 أهلاً! حسابك كمندوب جاهز'
      )
      navigate(selected === 'client' ? '/' : '/courier/dashboard', { replace: true })
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-orange-50 via-white to-amber-50 flex items-center justify-center p-4">
      <div className="w-full max-w-lg">

        {/* Header */}
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-orange-500 rounded-3xl flex items-center justify-center mx-auto mb-5 shadow-xl shadow-orange-200">
            <Truck className="text-white" size={36} />
          </div>
          <h1 className="text-3xl font-black text-gray-900 mb-2">
            أهلاً {user?.name?.split(' ')[0] || 'بيك'} 👋
          </h1>
          <p className="text-gray-500 text-lg">إزاي هتستخدم مندوبك؟</p>
        </div>

        {/* Role Cards */}
        <div className="grid grid-cols-2 gap-4 mb-8">

          {/* عميل */}
          <button
            onClick={() => setSelected('client')}
            className={`relative rounded-3xl p-6 border-2 transition-all duration-200 text-right flex flex-col items-start gap-3
              ${selected === 'client'
                ? 'border-blue-500 bg-blue-50 shadow-lg shadow-blue-100 scale-[1.02]'
                : 'border-gray-200 bg-white hover:border-blue-300 hover:bg-blue-50/50'}`}
          >
            {selected === 'client' && (
              <span className="absolute top-3 left-3 w-6 h-6 bg-blue-500 rounded-full flex items-center justify-center">
                <span className="text-white text-xs font-bold">✓</span>
              </span>
            )}
            <div className="w-14 h-14 bg-blue-100 rounded-2xl flex items-center justify-center">
              <ShoppingBag className="text-blue-600" size={28} />
            </div>
            <div>
              <div className="font-black text-xl text-gray-900 mb-1">عميل</div>
              <div className="text-sm text-gray-500 leading-relaxed">اطلب توصيل وتابع طلباتك</div>
            </div>
            <div className="flex flex-wrap gap-1 mt-1">
              {['طلب توصيل', 'تتبع مباشر', 'تقييم'].map(tag => (
                <span key={tag} className="text-xs bg-blue-100 text-blue-700 px-2 py-0.5 rounded-full font-medium">{tag}</span>
              ))}
            </div>
          </button>

          {/* مندوب */}
          <button
            onClick={() => setSelected('courier')}
            className={`relative rounded-3xl p-6 border-2 transition-all duration-200 text-right flex flex-col items-start gap-3
              ${selected === 'courier'
                ? 'border-orange-500 bg-orange-50 shadow-lg shadow-orange-100 scale-[1.02]'
                : 'border-gray-200 bg-white hover:border-orange-300 hover:bg-orange-50/50'}`}
          >
            {selected === 'courier' && (
              <span className="absolute top-3 left-3 w-6 h-6 bg-orange-500 rounded-full flex items-center justify-center">
                <span className="text-white text-xs font-bold">✓</span>
              </span>
            )}
            <div className="w-14 h-14 bg-orange-100 rounded-2xl flex items-center justify-center">
              <Truck className="text-orange-600" size={28} />
            </div>
            <div>
              <div className="font-black text-xl text-gray-900 mb-1">مندوب</div>
              <div className="text-sm text-gray-500 leading-relaxed">استقبل طلبات واكسب فلوس</div>
            </div>
            <div className="flex flex-wrap gap-1 mt-1">
              {['طلبات مباشرة', 'أرباح يومية', 'مرن'].map(tag => (
                <span key={tag} className="text-xs bg-orange-100 text-orange-700 px-2 py-0.5 rounded-full font-medium">{tag}</span>
              ))}
            </div>
          </button>
        </div>

        {/* Note for courier */}
        {selected === 'courier' && (
          <div className="bg-amber-50 border border-amber-200 rounded-2xl p-4 mb-6 text-right">
            <div className="text-amber-800 font-bold text-sm mb-1">📋 بعد الاختيار</div>
            <div className="text-amber-700 text-sm">
              هتحتاج تكمل تسجيل بيانات المندوب وصورة البطاقة عشان يتم قبولك.
            </div>
          </div>
        )}

        {/* Confirm Button */}
        <button
          onClick={handleConfirm}
          disabled={!selected || loading}
          className={`w-full py-4 rounded-2xl font-black text-lg transition-all duration-200 flex items-center justify-center gap-3
            ${selected && !loading
              ? 'bg-orange-500 text-white hover:bg-orange-600 shadow-lg shadow-orange-200 active:scale-95'
              : 'bg-gray-100 text-gray-400 cursor-not-allowed'}`}
        >
          {loading
            ? <><Loader2 size={20} className="animate-spin" /> جاري الحفظ...</>
            : <>{selected ? `ابدأ كـ${selected === 'client' ? 'عميل' : 'مندوب'}` : 'اختار أولاً'}{selected && <ChevronLeft size={20} />}</>
          }
        </button>

        <p className="text-center text-xs text-gray-400 mt-4">يمكنك تغيير دورك لاحقاً من الإعدادات</p>
      </div>
    </div>
  )
}
